    "lyricsHtml": "\n<span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"chord\" data-chord=\"G7\">G7</span>                     <span class=\"chord\" data-chord=\"C\">C</span>                          <span class=\"chord\" data-chord=\"G\">G</span>               <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Não era novidade que nessa parte da cidade</span>\n                          <span class=\"chord\" data-chord=\"Gm\">Gm</span>                           <span class=\"chord\" data-chord=\"A7\">A7</span>                           <span class=\"chord\" data-chord=\"Dm\">Dm</span>\n<span class=\"lyric-line\">A muito já se fazia de noite e de dia um samba da velha</span>\n\n<span class=\"lyric-line\">Não faltava vontade, não faltava coragem, não faltava uma ideia</span>\n                          <span class=\"chord\" data-chord=\"G#7\">G#7</span>                           <span class=\"chord\" data-chord=\"G7\">G7</span>                               <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Só podia dar samba o celeiro de bamba da Vila Pompeia</span>\n                       <span class=\"chord\" data-chord=\"Dm\">Dm</span>                          <span class=\"chord\" data-chord=\"G7\">G7</span>          <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Uma águia rasante voou espalhando ouro no ar</span>\n                       <span class=\"chord\" data-chord=\"C7\">C7</span>                                       <span class=\"chord\" data-chord=\"F\">F</span>\n<span class=\"lyric-line\">Então todo povo se uniu e se pois a cantar</span>\n                                 <span class=\"chord\" data-chord=\"Fm\">Fm</span>                                                                                    <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Debaixo de um viaduto se encontra um reduto que esconde um tesouro</span>\n<span class=\"chord\" data-chord=\"A7\">A7</span>                       <span class=\"chord\" data-chord=\"Dm\">Dm</span>                              <span class=\"chord\" data-chord=\"G7\">G7</span>                                <span class=\"chord\" data-chord=\"C\">C</span>        <span class=\"chord\" data-chord=\"C7\">C7</span>\n<span class=\"lyric-line\">Salve a Velha Guarda e o belo estandarte do Águia de Ouro</span>\n                                     <span class=\"chord\" data-chord=\"F\">F</span>                                   <span class=\"chord\" data-chord=\"Fm\">Fm</span>                                          <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Debaixo de um viaduto se encontra um reduto que esconde um tesouro</span>\n<span class=\"chord\" data-chord=\"A7\">A7</span>                        <span class=\"chord\" data-chord=\"Dm\">Dm</span>                             <span class=\"chord\" data-chord=\"G7\">G7</span>                               <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">Salve a Velha Guarda e o belo estandarte do Águia de Ouro</span>\n",
